// в”Җв”Җв”Җ Poids de drop basГ©s sur l'OVR (pas la raretГ©) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Plus un joueur est fort, plus il est rare Г  dropper
// Les poids sont calculГ©s dynamiquement selon l'OVR de chaque joueur

// Poids de drop par tranche d'OVR
function getDropWeight(rating) {
  if (rating >= 95) return 1;    // Ultra rare
  if (rating >= 92) return 3;
  if (rating >= 90) return 6;
  if (rating >= 87) return 15;
  if (rating >= 85) return 30;
  if (rating >= 82) return 70;
  if (rating >= 80) return 120;
  if (rating >= 77) return 200;
  if (rating >= 75) return 300;
  if (rating >= 72) return 400;
  if (rating >= 70) return 500;
  return 600;
}

// в”Җв”Җв”Җ Limite d'exemplaires par OVR в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function getCardLimit(rating) {
  if (rating >= 95) return 1;   // 1 seul au monde !
  if (rating >= 92) return 2;
  if (rating >= 90) return 3;
  if (rating >= 87) return 5;
  if (rating >= 85) return 10;
  if (rating >= 82) return 20;
  if (rating >= 80) return 40;
  if (rating >= 77) return 80;
  if (rating >= 75) return 150;
  if (rating >= 72) return 300;
  if (rating >= 70) return 500;
  return 2000;
}

// в”Җв”Җв”Җ Points PROGRESSIFS dans chaque tranche в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Un 73 a TOUJOURS plus de points qu'un 71 dans la tranche 70-74
// Formule : on mappe l'OVR exact Г  l'intГ©rieur de sa tranche
//
// Tranches :
//   OVR < 70   вҶ’  1 Г  10 pts
//   OVR 70-74  вҶ’ 10 Г  50 pts
//   OVR 75-79  вҶ’ 50 Г  75 pts
//   OVR 80-84  вҶ’ 75 Г  100 pts
//   OVR 85-89  вҶ’ 100 Г  250 pts
//   OVR 90-94  вҶ’ 250 Г  500 pts
//   OVR 95-99  вҶ’ 500 Г  1000 pts
//
// + petite variance alГ©atoire Вұ5% (un 73 reste toujours > un 71)
// + lucky pull 3% вҶ’ Г—2

function computePoints(player) {
  const ovr = player.rating;

  // DГ©finir la tranche
  let minPts, maxPts, minOvr, maxOvr;

  if (ovr >= 95) {
    minPts = 500; maxPts = 1000; minOvr = 95; maxOvr = 99;
  } else if (ovr >= 90) {
    minPts = 250; maxPts = 500;  minOvr = 90; maxOvr = 94;
  } else if (ovr >= 85) {
    minPts = 100; maxPts = 250;  minOvr = 85; maxOvr = 89;
  } else if (ovr >= 80) {
    minPts = 75;  maxPts = 100;  minOvr = 80; maxOvr = 84;
  } else if (ovr >= 75) {
    minPts = 50;  maxPts = 75;   minOvr = 75; maxOvr = 79;
  } else if (ovr >= 70) {
    minPts = 10;  maxPts = 50;   minOvr = 70; maxOvr = 74;
  } else {
    minPts = 1;   maxPts = 10;   minOvr = 60; maxOvr = 69;
  }

  // Position dans la tranche (0.0 вҶ’ 1.0)
  const position = (ovr - minOvr) / (maxOvr - minOvr);

  // Points de base : progressif dans la tranche
  const base = minPts + position * (maxPts - minPts);

  // Variance Вұ5% (assez faible pour garantir la progression)
  const variance = base * (Math.random() * 0.10 - 0.05);

  // Lucky pull 3% вҶ’ Г—2
  const lucky   = Math.random() < 0.03 ? 2 : 1;
  const isLucky = lucky === 2;

  const total = Math.max(1, Math.round((base + variance) * lucky));
  return { points: total, isLucky };
}

function getRandomPlayer(excludedNames = new Set()) {
  // Construire le pool en excluant les cartes dГ©jГ  toutes claimГ©es
  const available = PLAYERS.filter(p => !excludedNames.has(p.name));
  if (!available.length) return PLAYERS[Math.floor(Math.random() * PLAYERS.length)];

  // Calcul du poids total basГ© sur l'OVR de chaque joueur disponible
  const totalWeight = available.reduce((sum, p) => sum + getDropWeight(p.rating), 0);
  let rand = Math.random() * totalWeight;

  let chosen = available[available.length - 1];
  for (const p of available) {
    rand -= getDropWeight(p.rating);
    if (rand <= 0) { chosen = p; break; }
  }

  const { points, isLucky } = computePoints(chosen);
  return { ...chosen, points, isLucky };
}

function generateCard(player) { return { ...player, obtainedAt: Date.now() }; }

module.exports = { PLAYERS, getRandomPlayer, generateCard, getCardLimit };